8	void static OpenFolderAndSelectItem(std::wstring filepath) {
9	  filepath = std::filesystem::path(filepath).make_preferred().wstring();
10	  std::wstring directory = std::filesystem::path(filepath).parent_path();
11	
12	  HRESULT hr;
13	  hr = CoInitializeEx(0, COINIT_MULTITHREADED);
14	
15	  auto folder = ILCreateFromPath(directory.c_str());
16	  std::vector<LPITEMIDLIST> v;
17	  v.push_back(ILCreateFromPath(filepath.c_str()));
18	
19	  SHOpenFolderAndSelectItems(folder, v.size(), (LPCITEMIDLIST*)v.data(), 0);
20	
21	  for (auto idl : v) {
22	    ILFree(idl);
23	  }
24	  ILFree(folder);
25	  CoUninitialize();
26	}
27	
28	template <typename T, typename U>
29	inline static std::wstring DoFileDialog(HWND hwndOwner,
30	                                        LPCWSTR title,
31	                                        UINT filterSize,
32	                                        COMDLG_FILTERSPEC filter[],
33	                                        LPCWSTR filename,
34	                                        LPCWSTR defExt) {
35	  std::wstring path;
36	  CoInitialize(NULL);
37	  CComPtr<T> spFileDialog;
38	  if (SUCCEEDED(spFileDialog.CoCreateInstance(__uuidof(U)))) {
39	    spFileDialog->SetFileTypes(filterSize, filter);
40	    spFileDialog->SetTitle(title);
41	    if (filename)
42	      spFileDialog->SetFileName(filename);
43	
44	    spFileDialog->SetDefaultExtension(defExt);
45	    if (SUCCEEDED(spFileDialog->Show(hwndOwner))) {
46	      CComPtr<IShellItem> spResult;
47	      if (SUCCEEDED(spFileDialog->GetResult(&spResult))) {
48	        wchar_t* name;
49	        if (SUCCEEDED(spResult->GetDisplayName(SIGDN_FILESYSPATH, &name))) {
50	          path = name;
51	          CoTaskMemFree(name);
52	        }
53	      }
54	    }
55	  }
56	  CoUninitialize();
57	  return path;
58	}
