100	LRESULT DictManagementDialog::OnBackup(WORD, WORD code, HWND, BOOL&) {
101	  int sel = user_dict_list_.GetCurSel();
102	  if (sel < 0 || sel >= user_dict_list_.GetCount()) {
103	    MSG_BY_IDS(IDS_STR_SEL_EXPORT_DICT_NAME, IDS_STR_SAD,
104	               MB_OK | MB_ICONINFORMATION);
105	    return 0;
106	  }
107	  std::wstring path;
108	  {
109	    char dir[MAX_PATH] = {0};
110	    rime_get_api()->get_user_data_sync_dir(dir, _countof(dir));
111	    WCHAR wdir[MAX_PATH] = {0};
112	    MultiByteToWideChar(CP_ACP, 0, dir, -1, wdir, _countof(wdir));
113	    path = wdir;
114	  }
115	  if (_waccess_s(path.c_str(), 0) != 0 &&
116	      !CreateDirectoryW(path.c_str(), NULL) &&
117	      GetLastError() == ERROR_PATH_NOT_FOUND) {
118	    MSG_BY_IDS(IDS_STR_ERREXPORT_SYNC_UV, IDS_STR_SAD, MB_OK | MB_ICONERROR);
119	    return 0;
120	  }
121	  WCHAR dict_name[100] = {0};
122	  user_dict_list_.GetText(sel, dict_name);
123	  path += std::wstring(L"\\") + dict_name + L".userdb.txt";
124	  std::string dict_name_str = wtou8(dict_name);
125	  if (!api_->backup_user_dict(dict_name_str.c_str())) {
126	    MSG_BY_IDS(IDS_STR_ERR_EXPORT_UNKNOWN, IDS_STR_SAD, MB_OK | MB_ICONERROR);
127	    return 0;
128	  } else if (_waccess(path.c_str(), 0) != 0) {
129	    MSG_BY_IDS(IDS_STR_ERR_EXPORT_SNAP_LOST, IDS_STR_SAD, MB_OK | MB_ICONERROR);
130	    return 0;
131	  }
132	  OpenFolderAndSelectItem(path);
133	  return 0;
134	}
