136	LRESULT DictManagementDialog::OnRestore(WORD, WORD code, HWND, BOOL&) {
137	  CString open_str, dict_snapshot_str, kcss_dict_snapshot_str, all_files_str;
138	  open_str.LoadStringW(IDS_STR_OPEN);
139	  dict_snapshot_str.LoadStringW(IDS_STR_DICT_SNAPSHOT);
140	  kcss_dict_snapshot_str.LoadStringW(IDS_STR_KCSS_DICT_SNAPSHOT);
141	  all_files_str.LoadStringW(IDS_STR_ALL_FILES);
142	
143	  const std::wstring dict_snapshot_name =
144	      dict_snapshot_str + L" (*.userdb.txt)";
145	  const std::wstring kcss_dict_snapshot_name =
146	      kcss_dict_snapshot_str + L" (*.userdb.kct.snapshot)";
147	  const std::wstring all_files_name = all_files_str;
148	
149	  COMDLG_FILTERSPEC filter[3] = {
150	      {dict_snapshot_name.c_str(), L"*.userdb.txt"},
151	      {kcss_dict_snapshot_name.c_str(), L"*.userdb.kct.snapshot"},
152	      {all_files_name.c_str(), L"*.*"}};
153	
154	  std::wstring selected_path = DoFileDialog<IFileOpenDialog, FileOpenDialog>(
155	      m_hWnd, open_str, ARRAYSIZE(filter), filter, NULL, L"snapshot");
156	  if (!selected_path.empty()) {
157	    char path[MAX_PATH] = {0};
158	    WideCharToMultiByte(CP_UTF8, 0, selected_path.c_str(), -1, path,
159	                        _countof(path), NULL, NULL);
160	    if (!api_->restore_user_dict(path)) {
161	      MSG_BY_IDS(IDS_STR_ERR_UNKNOWN, IDS_STR_SAD, MB_OK | MB_ICONERROR);
162	    } else {
163	      MSG_BY_IDS(IDS_STR_ERR_SUCCESS, IDS_STR_HAPPY,
164	                 MB_OK | MB_ICONINFORMATION);
165	    }
166	  }
167	  return 0;
